// ─── Particle Canvas ─────────────────────────────────────────────────────────
function EmeraldParticles() {
  const ref = useRef(null);
  useEffect(() => {
    const c = ref.current;if (!c) return;
    const ctx = c.getContext("2d");
    c.width = c.offsetWidth;c.height = c.offsetHeight;
    const pts = Array.from({ length: 60 }, () => ({
      x: Math.random() * c.width, y: Math.random() * c.height,
      r: Math.random() * 1.8 + 0.3,
      vx: (Math.random() - 0.5) * 0.25, vy: -Math.random() * 0.35 - 0.05,
      a: Math.random() * 0.6 + 0.1, p: Math.random() * Math.PI * 2
    }));
    let raf;
    const draw = () => {
      ctx.clearRect(0, 0, c.width, c.height);
      pts.forEach((p) => {
        p.x += p.vx;p.y += p.vy;p.p += 0.018;
        if (p.y < -4) {p.y = c.height + 4;p.x = Math.random() * c.width;}
        const a = p.a * (0.5 + 0.5 * Math.sin(p.p));
        ctx.beginPath();ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(16,185,129,${a})`;ctx.fill();
      });
      raf = requestAnimationFrame(draw);
    };
    draw();return () => cancelAnimationFrame(raf);
  }, []);
  return <canvas ref={ref} style={{ position: "absolute", inset: 0, width: "100%", height: "100%", pointerEvents: "none", zIndex: 0 }} />;
}

