function SReceipt({ amount, cause, txResult, onDone, onSkip }) {
  const [choice, setChoice] = useState(null);
  const [contact, setContact] = useState("");
  const [busy, setBusy] = useState(false);

  const buildReceiptData = () => {
    const now = new Date();
    const date = now.toLocaleDateString("fr-FR");
    const time = now.toLocaleTimeString("fr-FR");
    const ref = txResult?.ref || txResult?.authCode || "---";
    return JSON.stringify({
      lines: [
      { align: "center", bold: true, size: 2, text: "SADAKA" },
      { align: "center", size: 1, text: "Association Iqraa" },
      { text: "________________________________" },
      { text: "" },
      { bold: true, text: "REÇU DE DON" },
      { text: `Date : ${date}` },
      { text: `Heure : ${time}` },
      { text: `Réf : ${ref}` },
      { text: "" },
      { text: `Cause : ${cause?.name || "Don ponctuel"}` },
      { bold: true, size: 2, text: `Montant : ${parseFloat(amount).toFixed(2)} €` },
      { text: "" },
      { text: "________________________________" },
      { align: "center", text: "Merci pour votre générosité" },
      { align: "center", text: "« La sadaqa éteint le péché" },
      { align: "center", text: "comme l'eau éteint le feu »" },
      { text: "" },
      { align: "center", size: 1, text: "Terminal SADAQA-01" }]

    });
  };

  const confirm = async () => {
    setBusy(true);
    if (choice === "print") await MyPOSSmartSDK.printReceipt(buildReceiptData());else
    if (choice === "email" && contact) await MyPOSSmartSDK.sendEmail();else
    if (choice === "sms" && contact) await MyPOSSmartSDK.sendSMS();
    setBusy(false);
    onDone();
  };

  const opts = [
  { id: "print", icon: "🖨", title: "Imprimer le ticket", desc: "Impression immédiate sur la borne", ph: null },
  { id: "email", icon: "✉", title: "Par e-mail", desc: "Reçu fiscal envoyé à votre adresse", ph: "votre@email.fr", type: "email" },
  { id: "sms", icon: "💬", title: "Par SMS", desc: "Lien de téléchargement", ph: "+33 6 XX XX XX XX", type: "tel" }];


  return (
    <div className="s-receipt">
      {/* Header */}
      <div style={{ padding: "20px 16px 4px", textAlign: "center", position: "relative", zIndex: 1 }}>
        <div style={{ fontFamily: "var(--font)", fontWeight: 700, fontSize: 18, color: "var(--white)", marginBottom: 4 }}>
          Souhaitez-vous un reçu ?
        </div>
        <div style={{ fontFamily: "var(--font2)", fontSize: 10, color: "var(--text2)", letterSpacing: 2, textTransform: "uppercase" }}>
          Choisissez votre format
        </div>
      </div>

      <div className="rec-opts">
        {opts.map((o) =>
        <div key={o.id}>
            <div className={`rec-opt ${choice === o.id ? "on" : ""}`}
          onClick={() => setChoice(choice === o.id ? null : o.id)}>
              <div className="rec-opt-icon">{o.icon}</div>
              <div style={{ flex: 1 }}>
                <div className="rec-opt-title">{o.title}</div>
                <div className="rec-opt-desc">{o.desc}</div>
              </div>
              {choice === o.id && <div className="rec-opt-check">✓</div>}
            </div>
            {choice === o.id && o.ph &&
          <input className="rec-input" type={o.type}
          value={contact} onChange={(e) => setContact(e.target.value)}
          placeholder={o.ph} autoFocus />
          }
          </div>
        )}
      </div>

      <div style={{ flex: 1 }} />

      <div style={{ padding: "8px 16px 16px" }}>
        <button className="k-cta"
        disabled={busy || choice && choice !== "print" && !contact}
        onClick={choice ? confirm : onDone}>
          {busy ? "Envoi en cours…" : choice ? "Confirmer" : "Terminer sans reçu"}
        </button>
        <span className="rec-skip" onClick={onSkip}>Passer cette étape</span>
      </div>
    </div>);

}

